# faster for initial segment of sequence
from itertools import count, islice
from sympy import divisors
def agen(): # generator of kangaroo numbers
    for q in count(3):
        base = 10**(q-1)
        for b in range(1, 10):
            cands = set()
            for d in range(0, 10):
                divs = divisors(t:=b*base+d)
                for div in divs:
                    if (joey_shift:=10*div) >= base:
                        break
                    k = t + joey_shift
                    if k%div == 0:
                        cands.add(k)
            if not cands: continue
            yield from sorted(cands)
print(list(islice(agen(), 52))) # _Michael S. Branicky_, May 16 2026

